import { mergeJSON } from '../utils/zcutils';
import { getAnimationConf } from '../utils/animationutils';

export function setBulletBuilderConfig() {
    let seriesOptions = this.config.series,
        commonOptions = this.config.common,
        animationOptions = getAnimationConf(commonOptions, seriesOptions, this.chart, 'bullet');

    this.builderC.targetMarker =
        seriesOptions && seriesOptions.targetMarker
            ? mergeJSON(commonOptions.targetMarker, seriesOptions.targetMarker, true)
            : commonOptions.targetMarker;
}
